﻿using System;
using System.Collections.Generic;
using System.Text;

namespace MMMapEditor
{
    public class MonsterInfo
    {
        public string Name { get; set; }
        public byte[] RawData { get; set; }
        public int Index { get; set; }

        // Дополнительные характеристики можно распарсить позже при необходимости
        public byte Level { get; set; }
        public byte HP { get; set; }
        public byte Attack { get; set; }
        public byte Defense { get; set; }
        public byte Experience { get; set; }

        public override string ToString()
        {
            return Name?.Trim() ?? $"Monster {Index}";
        }
    }

    public static class MonsterDatabase
    {
        private static List<MonsterInfo> _monsters = null;
        private static Dictionary<int, MonsterInfo> _monstersById = null;

        public static IReadOnlyList<MonsterInfo> Monsters
        {
            get
            {
                if (_monsters == null)
                    ParseMonsterData();
                return _monsters.AsReadOnly();
            }
        }

        public static MonsterInfo GetMonsterByIndex(int index)
        {
            if (_monstersById == null)
                ParseMonsterData();

            _monstersById.TryGetValue(index, out var monster);
            return monster;
        }

        public static string GetMonsterName(int index)
        {
            var monster = GetMonsterByIndex(index);
            return monster?.Name?.Trim() ?? $"Monster {index}";
        }

