            string[] hexBytes = hexData.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
            byte[] allBytes = new byte[hexBytes.Length];
            for (int i = 0; i < hexBytes.Length; i++)
            {
                allBytes[i] = Convert.ToByte(hexBytes[i], 16);
            }

            int index = 0;
            int monsterId = 0;

            while (index + 32 <= allBytes.Length)
            {
                byte[] monsterEntry = new byte[32];
                Array.Copy(allBytes, index, monsterEntry, 0, 32);

                var monster = ParseMonsterEntry(monsterEntry, monsterId);
                _monsters.Add(monster);
                _monstersById[monsterId] = monster;

                index += 32;
                monsterId++;
            }
        }

        private static MonsterInfo ParseMonsterEntry(byte[] data, int index)
        {
            var monster = new MonsterInfo
            {
                RawData = data,
                Index = index
            };

            // Имя монстра - первые 20 байт (или до первого нуля)
            int nameLength = 0;
            for (int i = 0; i < 20; i++)
            {
                if (data[i] == 0)
                    break;
                nameLength++;
            }

            if (nameLength > 0)
            {
                monster.Name = Encoding.ASCII.GetString(data, 0, nameLength).Trim();
            }
            else
            {
                monster.Name = $"Monster_{index}";
            }

            // Дополнительные характеристики (можно добавить при необходимости)
            // Level: data[20]
            // Attack: data[22]?
            // Defense: data[23]?
            // HP: data[24]?
            // Experience: data[26]?

            if (data.Length > 20)
                monster.Level = data[20];

            return monster;
        }
    }
